parameters.jsCode:
const md = $input.first().json.candidates[0].content.parts[0].text;
const fechaIso = new Date().toISOString().slice(0, 10);
const semana = `Semana del ${new Date(Date.now() - 7*86400000).toISOString().slice(0,10)} al ${fechaIso}`;
const markdownCompleto = `# Reporte ejecutivo SHE · ${semana}

${md}

---

_Generado automáticamente por LRAC-031 · Gemini Pro · ${fechaIso}_`;
return [{ json: { markdown: markdownCompleto, fecha: fechaIso, semana } }];
